package com.enterprise.services;

import org.apache.camel.CamelContext;

/**
 * Service utilizing external Camel dependencies.
 */
public class ConnectivityService {
    private CamelContext context;

    public void checkStatus() {
        System.out.println("Context status: " + context.getStatus());
    }
}

package com.enterprise.services;

public class OrderService {
    private AuditService auditService;
    private String env = "PROD";

    public void processOrder(String orderId, double amount) {
        System.out.println("Processing order " + orderId);
        auditService.logEvent("ORDER_PROCESSED", orderId);
    }
}

package com.enterprise.services;

public class AuditService {
    public void logEvent(String type, String data) {
        System.out.println("AUDIT: " + type + " | " + data);
    }
}
